"""Adversary strategy implementations for SentinelX."""
from __future__ import annotations

import random
from dataclasses import dataclass, field
from typing import Any, Dict, List


@dataclass
class Scenario:
    """A fully-specified fraud episode generated by a strategy."""

    fraud_type: str
    transaction: Dict[str, Any]
    user_profile: Dict[str, Any]

    # Hidden evidence — only revealed when agent queries
    velocity_data: Dict[str, Any] = field(default_factory=dict)
    device_history: Dict[str, Any] = field(default_factory=dict)
    ip_reputation: Dict[str, Any] = field(default_factory=dict)
    network_connections: List[Dict[str, Any]] = field(default_factory=list)
    behavioral_biometrics: Dict[str, Any] = field(default_factory=dict)
    active_sessions: List[Dict[str, Any]] = field(default_factory=list)
    temporal_pattern: Dict[str, Any] = field(default_factory=dict)
    business_registration: Dict[str, Any] = field(default_factory=dict)
    network_graph: Dict[str, Any] = field(default_factory=dict)

    # Ground truth
    is_fraud: bool = True
    structuring_detected: bool = False
    total_laundered_amount: float = 0.0


# ---------------------------------------------------------------------------
# Base strategy
# ---------------------------------------------------------------------------

class FraudStrategy:
    name: str = "base"

    def generate(self, task_id: str, seed: int, user_profile: Dict[str, Any]) -> Scenario:
        raise NotImplementedError


# ---------------------------------------------------------------------------
# Task 1: Stolen Card strategies
# ---------------------------------------------------------------------------

class HighVelocityStrategy(FraudStrategy):
    """Obvious stolen card — high velocity, location anomaly, new device, VPN."""

    name = "high_velocity"

    def generate(self, task_id: str, seed: int, user_profile: Dict[str, Any]) -> Scenario:
        rng = random.Random(seed)
        amounts = [rng.uniform(400, 2499) for _ in range(5)]

        txn_amount = round(rng.uniform(2000, 2499), 2)

        return Scenario(
            fraud_type="stolen_card",
            transaction={
                "transaction_id": f"TXN{seed:06d}",
                "amount": txn_amount,
                "merchant": "ElectronicsStore_3947",
                "location": "Miami, FL",
                "timestamp": "2024-04-02T03:47:00Z",
                "currency": "USD",
            },
            user_profile={
                "user_id": user_profile["user_id"],
                "account_age_days": user_profile["account_age_days"],
                "typical_location": user_profile["typical_location"],
                "typical_transaction_size": user_profile["typical_transaction_size"],
                "card_present_ratio": user_profile["card_present_ratio"],
            },
            velocity_data={
                "past_7_days_count": rng.randint(18, 35),
                "past_24_hours_count": rng.randint(8, 15),
                "past_1_hour_count": rng.randint(4, 7),
                "amounts": amounts,
                "locations": ["Miami, FL", "Orlando, FL", "Tampa, FL"],
                "typical_7_day_count": 3,
                "anomaly_score": 0.92,
            },
            device_history={
                "current_device": "New iPhone (never seen before)",
                "current_device_fingerprint": f"DEV{seed:08x}",
                "known_devices": [
                    {"device": user_profile.get("primary_device", "iPhone"), "last_seen": "2024-04-01T22:15:00Z", "trusted": True}
                ],
                "is_new_device": True,
                "device_risk_score": 0.88,
            },
            ip_reputation={
                "ip": "104.28.42.17",
                "type": "vpn_exit_node",
                "provider": "Cloudflare",
                "risk_score": 0.85,
                "country": "US",
                "is_hosting": True,
                "is_proxy": True,
                "is_vpn": True,
                "is_tor": False,
            },
            active_sessions=[
                {"device": "New iPhone", "location": "Miami, FL", "started": "2024-04-02T03:30:00Z", "current": True},
            ],
            is_fraud=True,
        )


class DeviceSpoofingStrategy(FraudStrategy):
    """Fraudster uses device emulator after being caught on velocity checks."""

    name = "device_spoofing"

    def generate(self, task_id: str, seed: int, user_profile: Dict[str, Any]) -> Scenario:
        rng = random.Random(seed)
        # Spaced-out transactions to defeat velocity
        txn_amount = round(rng.uniform(1500, 2499), 2)

        return Scenario(
            fraud_type="stolen_card",
            transaction={
                "transaction_id": f"TXN{seed:06d}",
                "amount": txn_amount,
                "merchant": "ElectronicsStore_3947",
                "location": user_profile["typical_location"],  # Faked location
                "timestamp": "2024-04-02T14:10:00Z",
                "currency": "USD",
            },
            user_profile={
                "user_id": user_profile["user_id"],
                "account_age_days": user_profile["account_age_days"],
                "typical_location": user_profile["typical_location"],
                "typical_transaction_size": user_profile["typical_transaction_size"],
                "card_present_ratio": user_profile["card_present_ratio"],
            },
            velocity_data={
                "past_7_days_count": 4,
                "past_24_hours_count": 2,
                "past_1_hour_count": 1,
                "amounts": [round(rng.uniform(100, 500), 2) for _ in range(4)],
                "locations": [user_profile["typical_location"]],
                "typical_7_day_count": 3,
                "anomaly_score": 0.22,  # Low — fraudster spaced out
            },
            device_history={
                "current_device": f"Emulated {user_profile.get('primary_device', 'iPhone')} (spoofed)",
                "current_device_fingerprint": f"EMU{seed:08x}",
                "known_devices": [
                    {"device": user_profile.get("primary_device", "iPhone"), "last_seen": "2024-04-01T20:00:00Z", "trusted": True}
                ],
                "is_new_device": True,
                "canvas_fingerprint_mismatch": True,
                "webgl_fingerprint_mismatch": True,
                "device_risk_score": 0.91,
            },
            ip_reputation={
                "ip": "45.33.32.156",
                "type": "datacenter",
                "provider": "Linode",
                "risk_score": 0.70,
                "country": "US",
                "is_hosting": True,
                "is_proxy": False,
                "is_vpn": False,
                "is_tor": False,
            },
            is_fraud=True,
        )


