class ShellNetworkStrategy(FraudStrategy):
    """Advanced: deeper shell layers, mules as intermediaries."""

    name = "shell_network"

    def generate(self, task_id: str, seed: int, user_profile: Dict[str, Any]) -> Scenario:
        # builds on StructuredPaymentsStrategy but adds extra hop
        base = StructuredPaymentsStrategy().generate(task_id, seed, user_profile)
        base.network_graph["depth_3"] = {
            "nodes": base.network_graph["depth_2"]["nodes"] + ["Mule_Account_01", "Mule_Account_02"],
            "edges": 11,
            "mule_accounts": ["Mule_Account_01", "Mule_Account_02"],
            "note": "Unwitting intermediaries used to obscure trail",
        }
        base.fraudster_strategy = "shell_network"
        return base


